import{c as s,Q as a,j as n,m as o}from"./chunks/framework.CBiVa4O3.js";const h=JSON.parse('{"title":"服务发现与配置中心","description":"","frontmatter":{},"headers":[],"relativePath":"../distributedLearning/29-服务发现与配置中心.md","filePath":"../distributedLearning/29-服务发现与配置中心.md","lastUpdated":1778496697000}'),r={name:"../distributedLearning/29-服务发现与配置中心.md"};function e(l,t,i,d,g,p){return a(),n("div",null,[...t[0]||(t[0]=[o(`<h1 id="服务发现与配置中心" tabindex="-1">服务发现与配置中心 <a class="header-anchor" href="#服务发现与配置中心" aria-label="Permalink to &quot;服务发现与配置中心&quot;">​</a></h1><p>微服务架构最先冒出来的问题不是&quot;怎么拆&quot;,而是**&quot;拆完之后,我怎么知道你在哪&quot;**。订单服务有 30 个实例,某个实例刚崩了,<strong>支付服务怎么不把请求打到那个死实例上</strong>?生产环境每天有几百次实例上下线、扩缩容、滚动发布,<strong>消费者必须实时知道&quot;谁还活着、在哪个 IP&quot;</strong>——这就是服务发现的使命。这一篇把 ZooKeeper / etcd / Consul / Eureka / Nacos 五大方案掰开,<strong>讲清楚 CP vs AP 的选型分水岭、为什么 K8s 选 etcd、为什么 Spring Cloud 选 Eureka、Netflix 那个臭名昭著的&quot;自我保护机制&quot;到底救人还是坑人</strong>。</p><blockquote><p>一句话先记住:<strong>服务发现解决「消费者怎么找到生产者」</strong>——核心是「<strong>注册中心</strong>」存着「服务名 → 实例列表」的映射,实例上下线时实时更新。<strong>最大的选型分歧是 CP 还是 AP</strong>——金融 / K8s 控制面要 CP(宁可暂时找不到也别给错地址),互联网业务多数要 AP(注册中心挂了不能拖累全局)。<strong>配置中心和服务发现常合并</strong>(Consul / Nacos / Apollo)——因为底层都是&quot;watch + 推送&quot;的同一套。</p></blockquote><hr><h2 id="一、不用服务发现的世界长什么样" tabindex="-1">一、不用服务发现的世界长什么样 <a class="header-anchor" href="#一、不用服务发现的世界长什么样" aria-label="Permalink to &quot;一、不用服务发现的世界长什么样&quot;">​</a></h2><p>最原始的方案:<strong>配置文件硬编码 IP</strong>。</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># order-service.yml</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">payment_service</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  hosts</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">10.1.2.3:8080</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">10.1.2.4:8080</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">10.1.2.5:8080</span></span></code></pre></div><p><strong>问题清单</strong>:</p><ol><li>某台机器挂了,要改配置 + 重启所有调用方</li><li>扩容了一台新机器,要改配置 + 重启</li><li>跨环境部署(dev/test/prod IP 不同),要维护多份配置</li><li>K8s 调度的 Pod IP 每次都变,配置文件追不上</li></ol><p><strong>结论</strong>:<strong>只要业务超过 5 个服务、超过 10 台机器,硬编码就死路一条</strong>。</p><h3 id="_1-1-加个-lb-也不够" tabindex="-1">1.1 加个 LB 也不够 <a class="header-anchor" href="#_1-1-加个-lb-也不够" aria-label="Permalink to &quot;1.1 加个 LB 也不够&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>order-service → 调用 nginx:8080 → 转发到后端实例</span></span></code></pre></div><p>Nginx 解决了&quot;客户端不感知 IP&quot;的问题,<strong>但 Nginx 自己怎么知道后端实例列表?</strong>——还是要有人把&quot;实例上下线&quot;告诉 Nginx,<strong>这件事就是服务注册中心干的</strong>。</p><blockquote><p>Nginx / Envoy / 网关都是&quot;服务发现的客户端&quot;,<strong>真正的核心是注册中心</strong>。</p></blockquote><hr><h2 id="二、客户端发现-vs-服务端发现" tabindex="-1">二、客户端发现 vs 服务端发现 <a class="header-anchor" href="#二、客户端发现-vs-服务端发现" aria-label="Permalink to &quot;二、客户端发现 vs 服务端发现&quot;">​</a></h2><p>两种工作模式,<strong>先决定走哪条</strong>:</p><h3 id="_2-1-客户端发现-client-side-discovery" tabindex="-1">2.1 客户端发现(Client-Side Discovery) <a class="header-anchor" href="#_2-1-客户端发现-client-side-discovery" aria-label="Permalink to &quot;2.1 客户端发现(Client-Side Discovery)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>注册中心(Eureka / Nacos)</span></span>
<span class="line"><span>        ▲</span></span>
<span class="line"><span>        │ 拉取实例列表</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>  ┌─────┴─────┐</span></span>
<span class="line"><span>  │ 客户端 SDK │ → 自己挑一个实例 → 直接调</span></span>
<span class="line"><span>  └───────────┘</span></span></code></pre></div><p><strong>代表</strong>:Netflix Eureka + Ribbon、Nacos + Spring Cloud Alibaba。</p><p><strong>优点</strong>:</p><ul><li>无中间层,网络一跳到位</li><li>客户端可以自定义负载均衡策略(权重、地域亲和、灰度规则)</li></ul><p><strong>缺点</strong>:</p><ul><li>客户端 SDK 要更新——多语言成本高</li><li>客户端逻辑变重(健康检查、负载均衡、重试都自己写)</li></ul><h3 id="_2-2-服务端发现-server-side-discovery" tabindex="-1">2.2 服务端发现(Server-Side Discovery) <a class="header-anchor" href="#_2-2-服务端发现-server-side-discovery" aria-label="Permalink to &quot;2.2 服务端发现(Server-Side Discovery)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                                                ┌── 实例 1</span></span>
<span class="line"><span>客户端 → 调用 service-name → 网关/LB / Service ─┼── 实例 2</span></span>
<span class="line"><span>                                  ↑              └── 实例 3</span></span>
<span class="line"><span>                                  │</span></span>
<span class="line"><span>                            注册中心(etcd / Consul)</span></span></code></pre></div><p><strong>代表</strong>:K8s Service(kube-proxy + iptables/IPVS)、Nginx + Consul Template、Envoy + xDS、Istio。</p><p><strong>优点</strong>:</p><ul><li>客户端无感——只调用一个固定地址(<code>service-name.namespace.svc.cluster.local</code>)</li><li>多语言天然支持(客户端不需要 SDK)</li><li>路由策略集中管理(在网关 / sidecar 层)</li></ul><p><strong>缺点</strong>:</p><ul><li>多一跳(虽然 K8s iptables/IPVS 是 kernel 级,几乎无延迟)</li><li>网关 / sidecar 自身的可用性是新单点</li></ul><blockquote><p><strong>K8s 选了服务端发现</strong>(Service + Endpoints + kube-proxy),<strong>Spring Cloud 早期选了客户端发现</strong>(Eureka + Ribbon),<strong>Service Mesh 时代 sidecar(Envoy)是&quot;客户端发现的服务端化&quot;</strong>——逻辑下沉到 sidecar,业务代码看起来还是客户端发现。</p></blockquote><hr><h2 id="三、注册中心的核心功能" tabindex="-1">三、注册中心的核心功能 <a class="header-anchor" href="#三、注册中心的核心功能" aria-label="Permalink to &quot;三、注册中心的核心功能&quot;">​</a></h2><p>不管哪种模式,注册中心都要做这三件事:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 注册   :服务启动时把自己(&quot;我是 order-service,IP=10.1.2.3:8080&quot;)写入注册中心</span></span>
<span class="line"><span>2. 健康检查:周期性确认实例是否还活着(心跳 / TTL / 主动 probe)</span></span>
<span class="line"><span>3. 通知   :实例变化时通知消费者(watch / 长轮询 / 推送)</span></span></code></pre></div><h3 id="_3-1-健康检查的三种实现" tabindex="-1">3.1 健康检查的三种实现 <a class="header-anchor" href="#_3-1-健康检查的三种实现" aria-label="Permalink to &quot;3.1 健康检查的三种实现&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方式</th><th>工作机制</th><th>失效感知速度</th><th>代表系统</th></tr></thead><tbody><tr><td><strong>临时节点 + Session</strong></td><td>实例与 ZK 维持 session,session 断了节点自动删</td><td>秒级(session timeout)</td><td>ZooKeeper</td></tr><tr><td><strong>TTL Lease</strong></td><td>实例周期续约,过期自动失效</td><td>秒级(lease TTL)</td><td>etcd</td></tr><tr><td><strong>心跳上报</strong></td><td>实例定期 PUT /heartbeat</td><td>30-90 秒(默认)</td><td>Eureka</td></tr><tr><td><strong>主动 Probe</strong></td><td>注册中心主动 ping 实例</td><td>自定义周期</td><td>Consul Health Check</td></tr></tbody></table><blockquote><p><strong>临时节点</strong>和 <strong>TTL Lease</strong> 本质相同——都是&quot;靠会话保活,断线就清除&quot;,<strong>前者是 ZK 的术语,后者是 etcd 的术语</strong>。<strong>Eureka 心跳上报</strong>最宽松,所以失效感知最慢。</p></blockquote><h3 id="_3-2-变更通知的两种实现" tabindex="-1">3.2 变更通知的两种实现 <a class="header-anchor" href="#_3-2-变更通知的两种实现" aria-label="Permalink to &quot;3.2 变更通知的两种实现&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方式</th><th>工作机制</th><th>代表</th></tr></thead><tbody><tr><td><strong>Watch / 长连接</strong></td><td>客户端订阅,服务端有变更立刻推</td><td>ZK / etcd / Nacos</td></tr><tr><td><strong>Long Polling</strong></td><td>客户端发请求挂着,服务端有变更立刻返回</td><td>Consul / Apollo</td></tr><tr><td><strong>客户端拉取</strong></td><td>客户端定时来问</td><td>Eureka(默认 30 秒)</td></tr></tbody></table><p><strong>Watch 最快但服务端压力大</strong>(每个客户端一个长连接),<strong>Long Polling 折中</strong>,<strong>定时拉取最简单但变更感知慢</strong>——Eureka 30 秒间隔意味着&quot;实例挂了之后最多 30 秒消费者还在用老地址&quot;。</p><hr><h2 id="四、五大主流方案对比" tabindex="-1">四、五大主流方案对比 <a class="header-anchor" href="#四、五大主流方案对比" aria-label="Permalink to &quot;四、五大主流方案对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>系统</th><th>一致性</th><th>协议</th><th>主要用途</th><th>健康检查</th><th>变更通知</th><th>代表使用方</th></tr></thead><tbody><tr><td><strong>ZooKeeper</strong></td><td>CP</td><td>ZAB</td><td>强一致协调 / 配置 / 选主</td><td>临时节点 + Session</td><td>Watch</td><td>Kafka / HBase / Dubbo(旧版)</td></tr><tr><td><strong>etcd</strong></td><td>CP</td><td>Raft</td><td>K8s 控制面 / 配置 / 服务发现</td><td>TTL Lease</td><td>Watch</td><td>K8s / CoreDNS / Rook</td></tr><tr><td><strong>Consul</strong></td><td>CP(Raft) + AP(Gossip)</td><td>Raft + Memberlist</td><td>服务发现 + 健康检查 + KV</td><td>Gossip + Health Check</td><td>Long Polling</td><td>HashiCorp 生态</td></tr><tr><td><strong>Eureka</strong></td><td>AP</td><td>自研(P2P 复制)</td><td>Spring Cloud 服务发现</td><td>心跳上报</td><td>客户端拉取</td><td>Netflix(已停止维护)</td></tr><tr><td><strong>Nacos</strong></td><td>AP(默认)/CP(可切换)</td><td>Distro(AP) + Raft(CP)</td><td>阿里系微服务发现 + 配置</td><td>心跳 / 主动 Probe</td><td>推送(UDP/长连接)</td><td>阿里 / 国内中小公司</td></tr></tbody></table><h3 id="_4-1-zookeeper-老牌强一致协调器" tabindex="-1">4.1 ZooKeeper:老牌强一致协调器 <a class="header-anchor" href="#_4-1-zookeeper-老牌强一致协调器" aria-label="Permalink to &quot;4.1 ZooKeeper:老牌强一致协调器&quot;">​</a></h3><ul><li><strong>共识协议</strong>:ZAB(类 Paxos,见 14 篇),写要多数派</li><li><strong>数据模型</strong>:树形 znode,临时节点表示活实例</li><li><strong>强项</strong>:<strong>强一致 + Watch 机制可靠</strong>,适合配置 / 选主</li><li><strong>弱点</strong>: <ul><li>部署运维复杂(JVM,需要单独的 ZK 集群)</li><li>写性能差(每次写要多数派确认),不适合频繁注册场景</li><li><strong>CP 系统,分区时少数派不可用</strong>——业务感知:跨机房分区的少数派那侧服务发现挂掉</li></ul></li><li><strong>典型用法</strong>:Kafka 用它存元数据、Dubbo 早期版本用它做注册中心、HBase 用它做 master election</li></ul><h3 id="_4-2-etcd-k8s-时代的赢家" tabindex="-1">4.2 etcd:K8s 时代的赢家 <a class="header-anchor" href="#_4-2-etcd-k8s-时代的赢家" aria-label="Permalink to &quot;4.2 etcd:K8s 时代的赢家&quot;">​</a></h3><ul><li><strong>共识协议</strong>:Raft(13 篇),Go 写的,接口 gRPC</li><li><strong>数据模型</strong>:KV(扁平 key,可加前缀过滤)</li><li><strong>强项</strong>:<strong>简洁 + Go 生态 + Raft 易理解</strong>,Watch 接口设计干净</li><li><strong>弱点</strong>: <ul><li>仍然是 CP,跨机房分区有少数派不可用问题</li><li>大集群下 Raft 写吞吐有限(&lt; 10K QPS)</li></ul></li><li><strong>典型用法</strong>:<strong>K8s 控制面唯一持久化存储</strong>——所有 Pod / Service / Deployment 都进 etcd</li></ul><blockquote><p><strong>为什么 K8s 选 etcd 不选 ZK</strong>:Google 内部 Borg 用 Chubby(类 ZK),K8s 团队最初也想用 ZK,<strong>但 ZK 的 Java 依赖 + 复杂 API + 弱社区文档让 K8s 团队转向 etcd</strong>——Go 写的、API 简洁、Raft 比 Paxos 易懂、CoreOS 团队主导(后被 RedHat 收购)。<strong>这一选改变了云原生十年的技术栈</strong>。</p></blockquote><h3 id="_4-3-consul-服务发现的全栈方案" tabindex="-1">4.3 Consul:服务发现的全栈方案 <a class="header-anchor" href="#_4-3-consul-服务发现的全栈方案" aria-label="Permalink to &quot;4.3 Consul:服务发现的全栈方案&quot;">​</a></h3><p>HashiCorp 出品,<strong>思想是分层</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>控制面: Raft(CP)→ 服务注册数据、KV 配置</span></span>
<span class="line"><span>数据面: Gossip / SWIM(AP)→ 成员管理、故障检测</span></span></code></pre></div><ul><li><strong>强项</strong>: <ul><li>服务发现 + 健康检查 + KV 配置 + DNS 接口(直接 dig 查实例)一体</li><li>跨数据中心原生支持(WAN Gossip)</li><li>健康检查比对手强大(HTTP / TCP / Script / TTL)</li></ul></li><li><strong>弱点</strong>: <ul><li>部署稍重(每节点一个 agent + 中心 server)</li><li>国内用得不多(社区生态偏英文世界)</li></ul></li></ul><p><strong>典型用法</strong>:<strong>HashiCorp 生态(Nomad / Vault / Terraform)的协调中枢</strong>,中型互联网公司选它做注册 + 配置一站式。</p><h3 id="_4-4-eureka-spring-cloud-的伴生品" tabindex="-1">4.4 Eureka:Spring Cloud 的伴生品 <a class="header-anchor" href="#_4-4-eureka-spring-cloud-的伴生品" aria-label="Permalink to &quot;4.4 Eureka:Spring Cloud 的伴生品&quot;">​</a></h3><p>Netflix OSS 出品,<strong>Spring Cloud Netflix 时代的事实标准</strong>:</p><ul><li><strong>AP 设计</strong>:<strong>节点之间 P2P 复制,任何一个节点都能读写</strong>,牺牲一致性换可用性</li><li><strong>强项</strong>: <ul><li>简单(Java 写,Spring Boot 应用)</li><li>客户端 SDK 成熟(Ribbon + Hystrix 组合拳)</li><li><strong>AP 设计在大集群下不会因为少数派挂掉影响业务</strong></li></ul></li><li><strong>弱点</strong>: <ul><li><strong>臭名昭著的&quot;自我保护机制&quot;</strong>(下面单独讲)</li><li>数据不强一致——同一时刻不同 Eureka 节点看到的实例列表可能不同</li><li>客户端默认 30 秒拉一次,<strong>实例下线后最多 30 秒还在用老地址</strong></li><li><strong>Netflix 已经停止 Eureka 2.0 开发</strong>,1.x 进入维护模式</li></ul></li></ul><h3 id="_4-5-nacos-阿里出品-国内主流" tabindex="-1">4.5 Nacos:阿里出品,国内主流 <a class="header-anchor" href="#_4-5-nacos-阿里出品-国内主流" aria-label="Permalink to &quot;4.5 Nacos:阿里出品,国内主流&quot;">​</a></h3><ul><li><strong>特性</strong>:<strong>支持 AP 和 CP 两种模式可切换</strong>(默认 AP)</li><li><strong>强项</strong>: <ul><li>服务发现 + 配置中心一体</li><li>推送机制(UDP + 长连接),变更感知快</li><li>支持权重 / 灰度 / 多环境</li><li>中文文档 + 阿里背书,国内中小公司大量采用</li></ul></li><li><strong>弱点</strong>: <ul><li>早期版本 bug 多(2.x 起稳定)</li><li><strong>AP/CP 切换语义复杂</strong>,不少团队踩坑</li></ul></li></ul><p><strong>典型用法</strong>:<strong>国内 Spring Cloud Alibaba 体系的注册 + 配置中心</strong>(替代 Eureka + Apollo)。</p><hr><h2 id="五、cp-vs-ap-服务发现的核心选型分水岭" tabindex="-1">五、CP vs AP:服务发现的核心选型分水岭 <a class="header-anchor" href="#五、cp-vs-ap-服务发现的核心选型分水岭" aria-label="Permalink to &quot;五、CP vs AP:服务发现的核心选型分水岭&quot;">​</a></h2><p>这是整个服务发现领域<strong>最核心的选型决策</strong>:</p><h3 id="_5-1-cp-派的逻辑" tabindex="-1">5.1 CP 派的逻辑 <a class="header-anchor" href="#_5-1-cp-派的逻辑" aria-label="Permalink to &quot;5.1 CP 派的逻辑&quot;">​</a></h3><p><strong>&quot;宁可暂时找不到服务,也别让消费者拿到错误地址&quot;</strong>。</p><ul><li>注册数据强一致——所有客户端任意时刻看到的实例列表完全相同</li><li>分区时少数派不可用——少数派 Eureka 客户端读不到注册中心,<strong>拒绝服务</strong>而不是返回旧数据</li></ul><p><strong>适合</strong>:</p><ul><li>K8s 控制面(Pod 调度不能容忍多源不一致)</li><li>配置数据(一份配置变更要立刻全网生效)</li><li>金融 / 银行系统(实例列表错就可能调错账户)</li></ul><h3 id="_5-2-ap-派的逻辑" tabindex="-1">5.2 AP 派的逻辑 <a class="header-anchor" href="#_5-2-ap-派的逻辑" aria-label="Permalink to &quot;5.2 AP 派的逻辑&quot;">​</a></h3><p><strong>&quot;注册中心挂了不能拖累全局,业务自己用旧地址试一下,挂了重试&quot;</strong>。</p><ul><li>注册数据最终一致——不同节点看到的实例列表可能短暂不同</li><li>分区时<strong>两边都能读写</strong>——少数派也能返回(可能过期的)实例列表</li></ul><p><strong>适合</strong>:</p><ul><li>互联网业务(注册中心 1 秒不可用就影响几百万 QPS,完全不能接受)</li><li>服务实例多(几千个),频繁上下线</li><li>业务侧已有重试 + 熔断兜底(详见 systemDesign/11/12 篇)</li></ul><h3 id="_5-3-主流选择" tabindex="-1">5.3 主流选择 <a class="header-anchor" href="#_5-3-主流选择" aria-label="Permalink to &quot;5.3 主流选择&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>主流选</th><th>理由</th></tr></thead><tbody><tr><td>互联网 To C 业务</td><td>AP(Eureka / Nacos AP)</td><td>注册中心不能拖累业务,旧地址试一下大不了重试</td></tr><tr><td>K8s 控制面</td><td>CP(etcd)</td><td>调度数据必须强一致</td></tr><tr><td>阿里 / 腾讯内部</td><td>AP(Nacos / 自研)</td><td>大规模,容忍最终一致</td></tr><tr><td>银行 / 支付核心</td><td>CP(ZK / etcd)</td><td>宁可降级,不要错调</td></tr><tr><td>中间件元数据(Kafka 早期)</td><td>CP(ZK)</td><td>broker 拓扑必须一致</td></tr></tbody></table><blockquote><p>Patrick Eugster 一句话:<strong>&quot;Distributed systems are hard. Choose your impossible carefully.&quot;</strong>——CP 还是 AP,不是技术问题,是**业务可以容忍什么&quot;不可能&quot;**的问题。</p></blockquote><hr><h2 id="六、eureka-的自我保护机制-救人还是坑人" tabindex="-1">六、Eureka 的自我保护机制:救人还是坑人? <a class="header-anchor" href="#六、eureka-的自我保护机制-救人还是坑人" aria-label="Permalink to &quot;六、Eureka 的自我保护机制:救人还是坑人?&quot;">​</a></h2><p>Eureka 有个出了名的争议特性:<strong>自我保护机制(Self-Preservation Mode)</strong>。</p><h3 id="_6-1-它做什么" tabindex="-1">6.1 它做什么 <a class="header-anchor" href="#_6-1-它做什么" aria-label="Permalink to &quot;6.1 它做什么&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>正常情况:</span></span>
<span class="line"><span>  实例失去心跳 → Eureka 在 90 秒后剔除它</span></span>
<span class="line"><span></span></span>
<span class="line"><span>自我保护触发:</span></span>
<span class="line"><span>  Eureka Server 看到&quot;15 分钟内心跳数掉了 85% 以上&quot;</span></span>
<span class="line"><span>  → 进入自我保护模式</span></span>
<span class="line"><span>  → 不再剔除任何实例(即使它们已经死了)</span></span>
<span class="line"><span>  → 直到心跳数恢复</span></span></code></pre></div><h3 id="_6-2-它的初衷" tabindex="-1">6.2 它的初衷 <a class="header-anchor" href="#_6-2-它的初衷" aria-label="Permalink to &quot;6.2 它的初衷&quot;">​</a></h3><p><strong>Eureka 不信任自己</strong>——心跳大量缺失可能是 Eureka Server 网络故障(不是实例真死了)。<strong>这种情况下剔除实例会导致大量误踢</strong>,业务受影响。<strong>所以宁可保留死实例(消费者重试就行),也别误踢健康的</strong>。</p><h3 id="_6-3-它的坑" tabindex="-1">6.3 它的坑 <a class="header-anchor" href="#_6-3-它的坑" aria-label="Permalink to &quot;6.3 它的坑&quot;">​</a></h3><p><strong>真的有大批实例死了</strong>(机房断电、Pod 批量崩溃),Eureka 也以为是自己网络问题,<strong>死实例留在列表里几小时</strong>,消费者持续往死实例发请求,熔断器没配好就雪崩。</p><p><strong>Netflix 自己的事故</strong>:某次大批实例真死了,Eureka 自我保护拒绝剔除,导致下游持续报错,<strong>最终运维手动关闭自我保护才恢复</strong>。</p><blockquote><p><strong>教训</strong>:<strong>&quot;宁可保留过期数据&quot;在大多数情况下是对的,但在大规模批量故障时就是错的</strong>。AP 的代价在异常场景下会被放大,<strong>业务侧必须有客户端健康探测 + 熔断</strong>作为兜底——别只信注册中心。</p></blockquote><hr><h2 id="七、配置中心-服务发现的-近亲" tabindex="-1">七、配置中心:服务发现的&quot;近亲&quot; <a class="header-anchor" href="#七、配置中心-服务发现的-近亲" aria-label="Permalink to &quot;七、配置中心:服务发现的&quot;近亲&quot;&quot;">​</a></h2><p>配置中心解决的是**&quot;动态配置怎么不重启就推到所有实例&quot;**:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>开发改了限流阈值 100 → 200</span></span>
<span class="line"><span>  → 推到配置中心</span></span>
<span class="line"><span>  → 所有实例 watch 到变更</span></span>
<span class="line"><span>  → 立刻应用新值,不重启</span></span></code></pre></div><h3 id="_7-1-为什么和服务发现常合并" tabindex="-1">7.1 为什么和服务发现常合并 <a class="header-anchor" href="#_7-1-为什么和服务发现常合并" aria-label="Permalink to &quot;7.1 为什么和服务发现常合并&quot;">​</a></h3><p>底层都是&quot;watch + 推送&quot;的同一套机制:</p><ul><li>服务发现:<strong>watch &quot;service-name 的实例列表&quot;</strong></li><li>配置中心:<strong>watch &quot;config-key 的值&quot;</strong></li></ul><p><strong>底层都是 KV 存储 + 长连接通知</strong>——一套基础设施同时干两件事。</p><p><strong>典型合并方案</strong>:</p><ul><li><strong>Consul</strong>:KV 存配置 + 服务发现一体</li><li><strong>Nacos</strong>:配置 + 注册一体</li><li><strong>etcd</strong>:K8s ConfigMap + Service 都在 etcd 里</li><li><strong>Apollo</strong>:<strong>纯配置中心</strong>,不做服务发现(携程开源)</li></ul><h3 id="_7-2-配置中心的额外特性" tabindex="-1">7.2 配置中心的额外特性 <a class="header-anchor" href="#_7-2-配置中心的额外特性" aria-label="Permalink to &quot;7.2 配置中心的额外特性&quot;">​</a></h3><p>普通 KV 不够,配置中心通常还要:</p><ul><li><strong>灰度发布</strong>:配置先推 1% 实例,观察一会儿再推全量</li><li><strong>多环境隔离</strong>:dev / test / prod 各自一份</li><li><strong>回滚</strong>:版本历史,一键回到上一版</li><li><strong>审计</strong>:谁改的、什么时候、为什么(合规要求)</li><li><strong>权限</strong>:某些配置只能特定人改</li></ul><p><strong>Apollo / Nacos / etcd + 工具链</strong>都能做,<strong>直接用 etcd 裸 KV 不够</strong>——这就是为什么 K8s 还需要 ConfigMap / Operator 之类的上层封装。</p><h3 id="_7-3-配置中心架构-以-apollo-为例" tabindex="-1">7.3 配置中心架构(以 Apollo 为例) <a class="header-anchor" href="#_7-3-配置中心架构-以-apollo-为例" aria-label="Permalink to &quot;7.3 配置中心架构(以 Apollo 为例)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    管理后台(配置编辑)</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>    ┌──────────┐  ←─── 异步通知</span></span>
<span class="line"><span>    │ ConfigDB │       ConfigService</span></span>
<span class="line"><span>    └──────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         │  watch / long polling</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>   ┌─────┴─────┐</span></span>
<span class="line"><span>   │  客户端 SDK │ → 缓存本地配置 → 应用代码读</span></span>
<span class="line"><span>   └───────────┘</span></span></code></pre></div><p><strong>Apollo 的设计点</strong>:</p><ul><li>客户端<strong>本地缓存配置</strong>——配置中心挂掉,业务用本地缓存继续跑</li><li>长轮询而非长连接——简化部署</li><li>配置变更秒级到客户端</li></ul><hr><h2 id="八、为什么-k8s-选-etcd-而不是-zk-consul" tabindex="-1">八、为什么 K8s 选 etcd 而不是 ZK / Consul <a class="header-anchor" href="#八、为什么-k8s-选-etcd-而不是-zk-consul" aria-label="Permalink to &quot;八、为什么 K8s 选 etcd 而不是 ZK / Consul&quot;">​</a></h2><p>K8s 早期讨论过用 ZK,<strong>最终选 etcd</strong>,核心原因:</p><h3 id="_8-1-技术原因" tabindex="-1">8.1 技术原因 <a class="header-anchor" href="#_8-1-技术原因" aria-label="Permalink to &quot;8.1 技术原因&quot;">​</a></h3><ul><li><strong>Go 同源</strong>:K8s 是 Go 写的,etcd 也是 Go 写的,<strong>SDK 无缝集成</strong></li><li><strong>Raft 比 ZAB / Paxos 易懂</strong>:K8s 团队需要 hack 共识层(成员变更、租约、压缩等),Raft 文档+实现成本低</li><li><strong>API 简洁</strong>:etcd 是 gRPC + KV,<strong>比 ZK 的 znode tree 简单</strong></li><li><strong>Lease + Watch 模型适合 K8s</strong>:每个 Pod 一个 lease,挂了自动清除,Endpoints 控制器 watch 到变更</li></ul><h3 id="_8-2-工程原因" tabindex="-1">8.2 工程原因 <a class="header-anchor" href="#_8-2-工程原因" aria-label="Permalink to &quot;8.2 工程原因&quot;">​</a></h3><ul><li><strong>CoreOS 团队主导</strong>(后被 RedHat 收购),配合 K8s 路线图深度优化</li><li><strong>社区文化</strong>:CoreOS / RedHat 生态偏云原生,Apache(ZK)偏传统 Java</li><li><strong>没有 JVM 依赖</strong>:JVM 启动慢、内存大,<strong>对控制面这种&quot;必须稳定&quot;的组件 Go 单二进制更友好</strong></li></ul><h3 id="_8-3-反面教材-k8s-etcd-挂了的事故" tabindex="-1">8.3 反面教材:K8s etcd 挂了的事故 <a class="header-anchor" href="#_8-3-反面教材-k8s-etcd-挂了的事故" aria-label="Permalink to &quot;8.3 反面教材:K8s etcd 挂了的事故&quot;">​</a></h3><p><strong>etcd 是 K8s 的单点</strong>——etcd 全挂等于整个控制面失控:</p><ul><li>不能调度新 Pod</li><li>现有 Pod 还能跑(kubelet 有本地缓存)</li><li>不能创建/删除任何资源</li></ul><p><strong>多次真实事故</strong>:</p><ul><li><strong>etcd 磁盘满</strong>:某公司日志写到 etcd 的 PV,disk 100%,etcd 不可写,K8s 失控</li><li><strong>etcd 网络分区</strong>:跨机房 etcd 集群分区,少数派那侧 API Server 拒绝写入</li><li><strong>etcd 内存爆</strong>:大集群(&gt;5000 节点)Watch 客户端太多,etcd 内存吃满</li></ul><p><strong>解决思路</strong>:</p><ul><li>etcd 独立物理资源(别和业务混部)</li><li>多实例 + 跨 AZ</li><li>监控 etcd 的 leader 切换、写延迟、磁盘使用</li><li><strong>大集群拆分</strong>——超过 5000 节点考虑拆多套 K8s 集群,而不是一套硬撑</li></ul><hr><h2 id="九、生产真实事故案例" tabindex="-1">九、生产真实事故案例 <a class="header-anchor" href="#九、生产真实事故案例" aria-label="Permalink to &quot;九、生产真实事故案例&quot;">​</a></h2><h3 id="_9-1-netflix-eureka-自我保护留死实例" tabindex="-1">9.1 Netflix Eureka 自我保护留死实例 <a class="header-anchor" href="#_9-1-netflix-eureka-自我保护留死实例" aria-label="Permalink to &quot;9.1 Netflix Eureka 自我保护留死实例&quot;">​</a></h3><p>某次 Netflix 实例批量崩溃,<strong>Eureka 自我保护拒绝剔除</strong>,下游服务持续把请求打到死实例,<strong>雪崩 30 分钟</strong>。Netflix 内部反思:<strong>自我保护是好心办坏事的典型,要配合客户端主动健康探测</strong>——别只依赖注册中心剔除。</p><h3 id="_9-2-k8s-etcd-挂导致整集群失控" tabindex="-1">9.2 K8s etcd 挂导致整集群失控 <a class="header-anchor" href="#_9-2-k8s-etcd-挂导致整集群失控" aria-label="Permalink to &quot;9.2 K8s etcd 挂导致整集群失控&quot;">​</a></h3><p>某互联网公司,<strong>etcd 三节点其中两台机器同一时间硬盘故障</strong>(同一批次磁盘,寿命到期),etcd 失去多数派,<strong>API Server 全部 503</strong>,几小时内不能扩缩容、不能发布、不能调度新 Pod。<strong>根因是 etcd 多节点放在同一批硬件</strong>——后来改为跨 AZ 部署。</p><h3 id="_9-3-zk-跨机房分区导致-dubbo-全网瘫痪" tabindex="-1">9.3 ZK 跨机房分区导致 Dubbo 全网瘫痪 <a class="header-anchor" href="#_9-3-zk-跨机房分区导致-dubbo-全网瘫痪" aria-label="Permalink to &quot;9.3 ZK 跨机房分区导致 Dubbo 全网瘫痪&quot;">​</a></h3><p>某公司 Dubbo + ZK 注册中心,<strong>ZK 集群跨两个机房</strong>(2+3 节点)。机房间网络断了,<strong>少数派机房的 Dubbo 客户端</strong>(2 节点 ZK 那边)读不到注册中心,<strong>全部服务调用失败</strong>。<strong>根因</strong>:ZK 是 CP,<strong>分区时少数派强一致地拒绝读</strong>——业务应该用 AP 或者跨机房 ZK 部署应避免 2+3 这种&quot;小机房会失联&quot;的拓扑。</p><h3 id="_9-4-nacos-ap-cp-切换导致数据丢失" tabindex="-1">9.4 Nacos AP/CP 切换导致数据丢失 <a class="header-anchor" href="#_9-4-nacos-ap-cp-切换导致数据丢失" aria-label="Permalink to &quot;9.4 Nacos AP/CP 切换导致数据丢失&quot;">​</a></h3><p>某团队把 Nacos 从 AP 切换到 CP,<strong>切换过程中正在写的注册数据丢了</strong>——AP 模式的 Distro 协议和 CP 模式的 Raft 协议存储不互通,<strong>切换不是热切换</strong>。<strong>根因</strong>:对 Nacos 双模式理解不够深,<strong>生产环境别频繁切</strong>。</p><hr><h2 id="十、踩坑提醒" tabindex="-1">十、踩坑提醒 <a class="header-anchor" href="#十、踩坑提醒" aria-label="Permalink to &quot;十、踩坑提醒&quot;">​</a></h2><ol><li><strong>混淆 CP/AP 选型语义</strong>——业务能接受&quot;实例列表偶尔不一致&quot;就用 AP(Eureka/Nacos),不能接受就用 CP(etcd/ZK)。<strong>互联网业务 90% 该选 AP</strong>。</li><li><strong>K8s 集群外部还往 etcd 塞数据</strong>——etcd 是 K8s 的私有存储,<strong>业务往里写 KV 是大忌</strong>,容易挤爆 etcd 影响控制面。<strong>业务配置走单独的 Consul / Nacos / Apollo</strong>。</li><li><strong>Eureka 不关自我保护就上生产</strong>——批量故障时它会拒绝剔除死实例,<strong>配合熔断器 + 客户端主动健康探测才稳</strong>。</li><li><strong>配置中心当 KV 数据库用</strong>——配置中心是给&quot;低频改、高频读&quot;的配置用的,<strong>频繁写会把 etcd / ZK 拖死</strong>。业务运行数据走 Redis / MySQL。</li><li><strong>不缓存注册数据</strong>——客户端不缓存,注册中心一抖就全网调用失败。<strong>SDK 必须本地缓存 + 异步刷新</strong>,注册中心挂了还能用最后一份。</li><li><strong>健康检查只检查端口存活</strong>——TCP 端口活着但应用线程死了(死锁、OOM 边缘),<strong>必须 HTTP /health 检查应用真实状态</strong>。</li><li><strong>跨机房 ZK 部署成 2+3</strong>——少数派机房网络分区时直接全部不可用。<strong>3 机房 1+1+1 或 5 节点跨 3 机房 2+2+1</strong>才稳。</li><li><strong>Eureka 心跳超时设得太长</strong>——默认 90 秒,<strong>死实例可能 1.5 分钟才被剔除</strong>,业务感知差。改 30 秒或 45 秒。</li><li><strong>配置变更不灰度直接全网推</strong>——一个错误配置(限流阈值、超时时间)推到所有实例,<strong>全部业务在 10 秒内崩</strong>。<strong>配置中心必须支持灰度推送</strong>,先 1% 实例观察。</li><li><strong>服务实例下线不优雅</strong>——直接 kill -9 实例,<strong>注册中心几秒内才感知</strong>,期间客户端继续打过来。<strong>优雅下线</strong>:实例先调 deregister API → 等 N 秒(让消费者刷新缓存)→ 再退出。</li></ol><hr><p>下一篇 <code>30-故障检测与脑裂</code>:<strong>服务发现解决了&quot;谁活着,在哪&quot;的元数据问题,但&quot;谁真的活着&quot;是个更深的问题</strong>——网络抖动让 A 看 B 死、B 看 A 死,**怎么不误判?**φ-accrual 故障检测 + Quorum 防脑裂 + Fencing Token + STONITH,<strong>收尾篇把整套&quot;分布式判生死&quot;的工具讲完</strong>,然后告诉读者 30 篇分布式理论的底层图景已经完整。</p>`,135)])])}const u=s(r,[["render",e]]);export{h as __pageData,u as default};
